17	`include "defines.svh"
18	
19	import defines::*;
20	
21	//
22	// This routes AXI transactions between two masters and two slaves
23	// mapped into different regions of a common address space.
24	// XXX this should be reworked to support an arbitrary number of
25	// controlling masters.
26	//
27	
28	module axi_interconnect
29	    #(parameter M1_BASE_ADDRESS = 32'hffffeee0)
30	
31	    (input                      clk,
32	    input                       reset,
33	
34	    // These interface control externally connected slaves
35	    // Slave Interface 0 (address 0x00000000 - M1_BASE_ADDRESS)
36	    // Slave Interface 1 (address M1_BASE_ADDRESS - 0xfffeffff)
37	    axi4_interface.master       axi_bus_s[1:0],
38	
39	    // These interfaces are controlled by externally connected masters.
40	    // Interface 1 is read only.
41	    axi4_interface.slave        axi_bus_m[1:0]);
42	
43	    typedef enum {
44	        STATE_ARBITRATE,
45	        STATE_ISSUE_ADDRESS,
46	        STATE_ACTIVE_BURST
47	    } burst_state_t;
48	
49	    burst_state_t write_state;
50	    logic[31:0] write_burst_address;
51	    logic[7:0] write_burst_length;    // Like axi_awlen, this is number of transfers minus 1
52	    logic write_slave_select;
53	    logic read_selected_master;
54	    logic read_selected_slave;
55	    logic[7:0] read_burst_length;    // Like axi_arlen, this is number of transfers minus one
56	    logic[31:0] read_burst_address;
57	    burst_state_t read_state;
58	    logic axi_arready_m;
59	    logic axi_rready_m;
60	    logic axi_rvalid_m;
61	
62	    //
63	    // Write handling. Only slave interface 0 does writes.
64	    // XXX I don't explicitly handle the response in the state machine, but it
65	    // works because everything is in the correct state when the transaction is finished.
66	    // This could introduce a subtle bug if the behavior of the core changed.
67	    //
68	
69	    // Since only slave interface 0 supports writes, just hard wire these.
70	    assign axi_bus_s[0].m_awaddr = write_burst_address;
71	    assign axi_bus_s[0].m_awlen = write_burst_length;
72	    assign axi_bus_s[0].m_wdata = axi_bus_m[0].m_wdata;
73	    assign axi_bus_s[0].m_wlast = axi_bus_m[0].m_wlast;
74	    assign axi_bus_s[0].m_bready = axi_bus_m[0].m_bready;
75	    assign axi_bus_s[1].m_awaddr = write_burst_address - M1_BASE_ADDRESS;
76	    assign axi_bus_s[1].m_awlen = write_burst_length;
77	    assign axi_bus_s[1].m_wdata = axi_bus_m[0].m_wdata;
78	    assign axi_bus_s[1].m_wlast = axi_bus_m[0].m_wlast;
79	    assign axi_bus_s[1].m_bready = axi_bus_m[0].m_bready;
80	
81	    assign axi_bus_s[0].m_awvalid = write_slave_select == 0 && write_state == STATE_ISSUE_ADDRESS;
82	    assign axi_bus_s[1].m_awvalid = write_slave_select == 1 && write_state == STATE_ISSUE_ADDRESS;
83	
84	    always_ff @(posedge clk, posedge reset)
85	    begin
86	        if (reset)
87	        begin
88	            write_state <= STATE_ARBITRATE;
89	            /*AUTORESET*/
90	            // Beginning of autoreset for uninitialized flops
91	            write_burst_address <= '0;
92	            write_burst_length <= '0;
93	            write_slave_select <= '0;
94	            // End of automatics
95	        end
96	        else if (write_state == STATE_ACTIVE_BURST)
97	        begin
98	            // Burst is active.  Check to see when it is finished.
99	            if (axi_bus_m[0].s_wready && axi_bus_m[0].m_wvalid)
100	            begin
101	                write_burst_length <= write_burst_length - 8'd1;
102	                if (write_burst_length == 0)
103	                    write_state <= STATE_ARBITRATE;
104	            end
105	        end
106	        else if (write_state == STATE_ISSUE_ADDRESS)
107	        begin
108	            // Wait for the slave to accept the address and length
109	            if (axi_bus_m[0].s_awready)
110	                write_state <= STATE_ACTIVE_BURST;
111	        end
112	        else if (axi_bus_m[0].m_awvalid)
113	        begin
114	            // Start a new write transaction
115	            write_slave_select <=  axi_bus_m[0].m_awaddr >= M1_BASE_ADDRESS;
116	            write_burst_address <= axi_bus_m[0].m_awaddr;
117	            write_burst_length <= axi_bus_m[0].m_awlen;
118	            write_state <= STATE_ISSUE_ADDRESS;
119	        end
120	    end
121	
122	    always_comb
123	    begin
124	        if (write_slave_select == 0)
125	        begin
126	            // Master Interface 0 is selected
127	            axi_bus_s[0].m_wvalid = axi_bus_m[0].m_wvalid && write_state == STATE_ACTIVE_BURST;
128	            axi_bus_s[1].m_wvalid = 0;
129	            axi_bus_m[0].s_awready = axi_bus_s[0].s_awready && write_state == STATE_ISSUE_ADDRESS;
130	            axi_bus_m[0].s_wready = axi_bus_s[0].s_wready && write_state == STATE_ACTIVE_BURST;
131	            axi_bus_m[0].s_bvalid = axi_bus_s[0].s_bvalid;
132	        end
133	        else
134	        begin
135	            // Master interface 1 is selected
136	            axi_bus_s[0].m_wvalid = 0;
137	            axi_bus_s[1].m_wvalid = axi_bus_m[0].m_wvalid && write_state == STATE_ACTIVE_BURST;
138	            axi_bus_m[0].s_awready = axi_bus_s[1].s_awready && write_state == STATE_ISSUE_ADDRESS;
139	            axi_bus_m[0].s_wready = axi_bus_s[1].s_wready && write_state == STATE_ACTIVE_BURST;
140	            axi_bus_m[0].s_bvalid = axi_bus_s[1].s_bvalid;
141	        end
142	    end
143	
144	    //
145	    // Read handling.  Slave interface 1 has priority.
146	    //
147	    assign axi_arready_m = read_selected_slave ? axi_bus_s[1].s_arready : axi_bus_s[0].s_arready;
148	    assign axi_rready_m = read_selected_slave ? axi_bus_s[1].m_rready : axi_bus_s[0].m_rready;
149	    assign axi_rvalid_m = read_selected_slave ? axi_bus_s[1].s_rvalid : axi_bus_s[0].s_rvalid;
150	
151	    always_ff @(posedge clk, posedge reset)
152	    begin
153	        if (reset)
154	        begin
155	            read_state <= STATE_ARBITRATE;
156	
157	            /*AUTORESET*/
158	            // Beginning of autoreset for uninitialized flops
159	            read_burst_address <= '0;
160	            read_burst_length <= '0;
161	            read_selected_master <= '0;
162	            read_selected_slave <= '0;
163	            // End of automatics
164	        end
165	        else if (read_state == STATE_ACTIVE_BURST)
166	        begin
167	            // Burst is active.  Check to see when it is finished.
168	            if (axi_rready_m && axi_rvalid_m)
169	            begin
170	                read_burst_length <= read_burst_length - 8'd1;
171	                if (read_burst_length == 0)
172	                    read_state <= STATE_ARBITRATE;
173	            end
174	        end
175	        else if (read_state == STATE_ISSUE_ADDRESS)
176	        begin
177	            // Wait for the slave to accept the address and length
178	            if (axi_arready_m)
179	                read_state <= STATE_ACTIVE_BURST;
180	        end
181	        else if (axi_bus_m[1].m_arvalid)
182	        begin
183	            // Start a read burst from slave 1
184	            read_state <= STATE_ISSUE_ADDRESS;
185	            read_burst_address <= axi_bus_m[1].m_araddr;
186	            read_burst_length <= axi_bus_m[1].m_arlen;
187	            read_selected_master <= 1'b1;
188	            read_selected_slave <= axi_bus_m[1].m_araddr >= M1_BASE_ADDRESS;
189	        end
190	        else if (axi_bus_m[0].m_arvalid)
191	        begin
192	            // Start a read burst from slave 0
193	            read_state <= STATE_ISSUE_ADDRESS;
194	            read_burst_address <= axi_bus_m[0].m_araddr;
195	            read_burst_length <= axi_bus_m[0].m_arlen;
196	            read_selected_master <= 1'b0;
197	            read_selected_slave <= axi_bus_m[0].m_araddr[31:28] != 0;
198	        end
199	    end
200	
201	    always_comb
202	    begin
203	        if (read_state == STATE_ARBITRATE)
204	        begin
205	            axi_bus_m[0].s_rvalid = 0;
206	            axi_bus_m[1].s_rvalid = 0;
207	            axi_bus_s[0].m_rready = 0;
208	            axi_bus_s[1].m_rready = 0;
209	            axi_bus_m[0].s_arready = 0;
210	            axi_bus_m[1].s_arready = 0;
211	        end
212	        else if (read_selected_master == 0)
213	        begin
214	            axi_bus_m[0].s_rvalid = axi_rvalid_m;
215	            axi_bus_m[1].s_rvalid = 0;
216	            axi_bus_s[0].m_rready = axi_bus_m[0].m_rready && read_selected_slave == 0;
217	            axi_bus_s[1].m_rready = axi_bus_m[0].m_rready && read_selected_slave == 1;
218	            axi_bus_m[0].s_arready = axi_arready_m && read_state == STATE_ISSUE_ADDRESS;
219	            axi_bus_m[1].s_arready = 0;
220	        end
221	        else
222	        begin
223	            axi_bus_m[0].s_rvalid = 0;
224	            axi_bus_m[1].s_rvalid = axi_rvalid_m;
225	            axi_bus_s[0].m_rready = axi_bus_m[1].m_rready && read_selected_slave == 0;
226	            axi_bus_s[1].m_rready = axi_bus_m[1].m_rready && read_selected_slave == 1;
227	            axi_bus_m[0].s_arready = 0;
228	            axi_bus_m[1].s_arready = axi_arready_m && read_state == STATE_ISSUE_ADDRESS;
229	        end
230	    end
231	
232	    assign axi_bus_s[0].m_arvalid = read_state == STATE_ISSUE_ADDRESS && read_selected_slave == 0;
233	    assign axi_bus_s[1].m_arvalid = read_state == STATE_ISSUE_ADDRESS && read_selected_slave == 1;
234	    assign axi_bus_s[0].m_araddr = read_burst_address;
235	    assign axi_bus_s[1].m_araddr = read_burst_address - M1_BASE_ADDRESS;
236	    assign axi_bus_m[0].s_rdata = read_selected_slave ? axi_bus_s[1].s_rdata : axi_bus_s[0].s_rdata;
237	    assign axi_bus_m[1].s_rdata = axi_bus_m[0].s_rdata;
238	    assign axi_bus_m[1].s_awready = '0;
239	    assign axi_bus_m[1].s_wready = '0;
240	    assign axi_bus_m[1].s_bvalid = '0;
241	
242	    // We end up reusing read_burst_length to track how many beats are left
243	    // later.  At this point, the value of ARLEN should be ignored by slave
244	    // we are driving, so it won't break anything.
245	    assign axi_bus_s[0].m_arlen = read_burst_length;
246	    assign axi_bus_s[1].m_arlen = read_burst_length;
247	endmodule
